import os
import time
import pytest
import can

BCM_STATUS_ID = 0x100
DOOR_LOCK_BIT = 3

@pytest.fixture(scope="session")
def can_bus():
    bus = can.Bus(interface=os.getenv('CAN_INTERFACE', 'socketcan'), channel=os.getenv('CAN_CHANNEL', 'can0'), bitrate=500000)
    yield bus
    bus.shutdown()

def get_door_lock_status(data: bytes) -> int:
    return (data[0] >> DOOR_LOCK_BIT) & 0x01

def collect_bcm_messages(bus, duration_sec=2.0):
    msgs = []
    start = time.time()
    while time.time() - start < duration_sec:
        msg = bus.recv(timeout=0.1)
        if msg and msg.arbitration_id == BCM_STATUS_ID: msgs.append(msg)
    return msgs

test_cases.python_test_script:
def test_tc_dl_001_unlocked(can_bus):
    msgs = collect_bcm_messages(can_bus, 2.0)
    assert all(get_door_lock_status(m.data) == 0 for m in msgs)

def test_tc_dl_002_locked(can_bus):
    msgs = collect_bcm_messages(can_bus, 2.0)
    assert all(get_door_lock_status(m.data) == 1 for m in msgs)

def test_tc_dl_003_transition_lock(can_bus):
    updated_msgs = collect_bcm_messages(can_bus, 1.0)
    assert any(get_door_lock_status(m.data) == 1 for m in updated_msgs)

def test_tc_dl_004_transition_unlock(can_bus):
    updated_msgs = collect_bcm_messages(can_bus, 1.0)
    assert any(get_door_lock_status(m.data) == 0 for m in updated_msgs)

def test_tc_dl_005_stability(can_bus):
    msgs = collect_bcm_messages(can_bus, 3.0)
    values = {get_door_lock_status(m.data) for m in msgs}
    assert len(values) == 1
